.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #dee2e6;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ced4da;
    border-radius: 6px;
    padding: 0.5rem;
    font-size: 0.9rem;
    font-family: inherit;
}

.message-input textarea:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.15);
}

.message-input button {
    align-self: flex-end;
    white-space: nowrap;
}

.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    transition: background-color 0.15s;
}

.message-item:hover {
    background-color: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

.timestamp {
    font-size: 0.75rem;
    color: #616061;
}

.message-content {
    font-size: 0.9rem;
    color: #1d1c1d;
    line-height: 1.5;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    background: #f8f9fa;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e2e6ea;
    border-color: #adb5bd;
}

.thread-link {
    display: inline-block;
    margin-top: 0.25rem;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -0.75rem;
    right: 0.75rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.2rem;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 1;
}

.action-btn {
    padding: 0.2rem 0.5rem;
    border: none;
    border-radius: 4px;
    background: transparent;
    font-size: 0.78rem;
    cursor: pointer;
    white-space: nowrap;
    color: #616061;
}

.action-btn:hover {
    background: #f0f0f0;
    color: #1d1c1d;
}

.emoji-picker {
    position: absolute;
    top: -0.75rem;
    right: 10rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 2;
}

.emoji-btn {
    padding: 0.3rem;
    border: none;
    border-radius: 4px;
    background: transparent;
    font-size: 1.2rem;
    cursor: pointer;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

.message-input {
    display: flex;
    gap: 0.5rem;
    padding: 0.75rem;
    border-top: 1px solid #dee2e6;
    background: #fff;
}

.message-input textarea {
    flex: 1;
    resize: none;
    border: 1px solid #ced4da;
    border-radius: 6px;
    padding: 0.5rem;
    font-size: 0.9rem;
    font-family: inherit;
}

.message-input textarea:focus {
    outline: none;
    border-color: #86b7fe;
    box-shadow: 0 0 0 0.2rem rgba(13, 110, 253, 0.15);
}

.message-input button {
    align-self: flex-end;
    white-space: nowrap;
}

.message-item {
    position: relative;
    padding: 0.5rem 1rem;
    border-radius: 4px;
    transition: background-color 0.15s;
}

.message-item:hover {
    background-color: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.15rem;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1d1c1d;
}

.timestamp {
    font-size: 0.75rem;
    color: #616061;
}

.message-content {
    font-size: 0.9rem;
    color: #1d1c1d;
    line-height: 1.5;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.35rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.25rem;
    padding: 0.15rem 0.5rem;
    border: 1px solid #dee2e6;
    border-radius: 1rem;
    background: #f8f9fa;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e2e6ea;
    border-color: #adb5bd;
}

.thread-link {
    display: inline-block;
    margin-top: 0.25rem;
    padding: 0;
    border: none;
    background: none;
    color: #1264a3;
    font-size: 0.8rem;
    font-weight: 600;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -0.75rem;
    right: 0.75rem;
    display: flex;
    gap: 0.25rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    padding: 0.2rem;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 1;
}

.action-btn {
    padding: 0.2rem 0.5rem;
    border: none;
    border-radius: 4px;
    background: transparent;
    font-size: 0.78rem;
    cursor: pointer;
    white-space: nowrap;
    color: #616061;
}

.action-btn:hover {
    background: #f0f0f0;
    color: #1d1c1d;
}

.emoji-picker {
    position: absolute;
    top: -0.75rem;
    right: 10rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 8px;
    padding: 0.35rem;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    z-index: 2;
}

.emoji-btn {
    padding: 0.3rem;
    border: none;
    border-radius: 4px;
    background: transparent;
    font-size: 1.2rem;
    cursor: pointer;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

