.channel-sidebar {
    flex: 0 0 250px;
    display: flex;
    flex-direction: column;
    background: #3f0e40;
    color: #fff;
    overflow-y: auto;
}

.sidebar-title {
    padding: 1rem 1rem 0.5rem;
    font-size: 1.1rem;
    font-weight: 700;
    color: #fff;
    margin: 0;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
}

.channel-item {
    padding: 0.5rem 1rem;
    cursor: pointer;
    transition: background-color 0.15s;
    border-left: 3px solid transparent;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.1);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.15);
    border-left-color: #fff;
}

.channel-name-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
}

.channel-description {
    font-size: 0.75rem;
    color: rgba(255, 255, 255, 0.6);
    margin-top: 0.1rem;
    overflow: hidden;
    text-overflow: ellipsis;
    white-space: nowrap;
}

.unread-badge {
    font-size: 0.7rem;
    padding: 0.15rem 0.45rem;
    border-radius: 10px;
}

@inject IJSRuntime JS

<div class="message-area">
    <div class="message-area-header">
        <h5># @Channel?.Name</h5>
        <span class="channel-desc">@Channel?.Description</span>
    </div>

    <div class="message-list" @ref="messageListRef">
        @if (HasMoreMessages)
        {
            <div class="load-more">
                <button class="btn btn-sm btn-outline-secondary" @onclick="LoadMore" disabled="@isLoadingMore">
                    @(isLoadingMore ? "Loading…" : "Load older messages")
                </button>
            </div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadSummary="GetThreadSummary(message.Id)"
                         OnOpenThread="OnOpenThread"
                         OnReact="OnReact" />
        }
    </div>

    <MessageInput Placeholder="@($"Message #{Channel?.Name}")" OnSend="HandleSend" />
</div>

@code {
    [Parameter] public Channel? Channel { get; set; }
    [Parameter, EditorRequired] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; }

    private ElementReference messageListRef;
    private bool isLoadingMore;
    private int? previousChannelId;
    private int previousMessageCount;
    private bool shouldScrollToBottom;

    protected override void OnParametersSet()
    {
        if (Channel?.Id != previousChannelId)
        {
            previousChannelId = Channel?.Id;
            shouldScrollToBottom = true;
            previousMessageCount = Messages.Count;
        }
        else if (Messages.Count > previousMessageCount && Messages.Count > 0)
        {
            // New message appended at the end — scroll down
            shouldScrollToBottom = !isLoadingMore;
            previousMessageCount = Messages.Count;
        }
    }

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (shouldScrollToBottom)
        {
            shouldScrollToBottom = false;
            await JS.InvokeVoidAsync("chatInterop.scrollToBottom", messageListRef);
        }
    }

    private async Task HandleSend(string content)
    {
        await OnSendMessage.InvokeAsync(content);
        shouldScrollToBottom = true;
    }

    private async Task LoadMore()
    {
        isLoadingMore = true;
        await OnLoadMore.InvokeAsync();
        isLoadingMore = false;
    }

    private ThreadSummary? GetThreadSummary(int messageId)
        => ThreadSummaries.GetValueOrDefault(messageId);
}

