{"file_text": "<div class="thread-panel">
    <div class="thread-header">
        <h6>Thread</h6>
        <button class="btn-close" @onclick="OnClose" aria-label="Close thread"></button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <span class="author">@RootMessage.Author</span>
            <p class="root-content">@RootMessage.Content</p>
        </div>

        <hr class="thread-divider" />

        <div class="thread-replies">
            @if (Replies.Count == 0)
            {
                <p class="no-replies">No replies yet</p>
            }
            @foreach (var reply in Replies)
            {
                <div class="thread-reply">
                    <div class="reply-header">
                        <span class="author">@reply.Author</span>
                        <span class="timestamp">@FormatRelativeTime(reply.SentAt)</span>
                    </div>
                    <div class="reply-content">@reply.Content</div>
                </div>
            }
        </div>

        <MessageInput Placeholder="Reply in thread…" ButtonText="Reply" OnSend="OnSendReply" />
    }
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public List<Message> Replies { get; set; } = [];
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 0) return "just now";
        if (diff.TotalMinutes < 1) return "just now";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}
