arguments.file_text:
@page "/chat"
@layout ChatLayout
@rendermode InteractiveServer
@using sv_5a002f7d23e64232a2018aac29c2fb9b.Services
@inject IChatService ChatService
@inject IJSRuntime JS

<PageTitle>Chat</PageTitle>

<div class="chat-container">
    <ChannelSidebar Channels="channels"
                    ActiveChannelId="activeChannel?.Id"
                    OnChannelSelected="SelectChannel" />

    <MessageArea Channel="activeChannel"
                 Messages="messages"
                 ThreadSummaries="threadSummaries"
                 HasMoreMessages="hasMoreMessages"
                 OnSendMessage="SendMessage"
                 OnOpenThread="OpenThread"
                 OnReact="AddReaction"
                 OnLoadMore="LoadMoreMessages" />

    @if (isThreadOpen)
    {
        <ThreadPanel RootMessage="threadRootMessage"
                     Replies="threadReplies"
                     OnClose="CloseThread"
                     OnSendReply="SendThreadReply" />
    }
</div>

@code {
    private List<Channel> channels = [];
    private Channel? activeChannel;
    private List<Message> messages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();
    private bool hasMoreMessages = true;

    private bool isThreadOpen;
    private Message? threadRootMessage;
    private List<Message> threadReplies = [];

    private const int PageSize = 50;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();
        if (channels.Count > 0)
        {
            await SelectChannel(channels[0]);
        }
    }

    private async Task SelectChannel(Channel channel)
    {
        activeChannel = channel;
        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
        hasMoreMessages = messages.Count >= PageSize;
        threadSummaries.Clear();
        CloseThread();

        await ChatService.MarkChannelReadAsync(channel.Id);

        var idx = channels.FindIndex(c => c.Id == channel.Id);
        if (idx >= 0)
        {
            channels[idx] = channel with { UnreadCount = 0 };
        }
    }

    private async Task SendMessage(string content)
    {
        if (activeChannel is null) return;
        var message = await ChatService.SendMessageAsync(activeChannel.Id, content, null);
        messages.Add(message);
    }

    private async Task LoadMoreMessages()
    {
        if (activeChannel is null) return;
        var older = await ChatService.GetMessagesAsync(activeChannel.Id, messages.Count, PageSize);
        if (older.Count < PageSize) hasMoreMessages = false;
        messages.InsertRange(0, older);
    }

    private async Task OpenThread(int messageId)
    {
        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
        if (threadRootMessage is null) return;

        threadReplies = await ChatService.GetThreadAsync(messageId);
        isThreadOpen = true;

        threadSummaries[messageId] = new ThreadSummary(
            messageId,
            threadReplies.Count,
            threadReplies.Count > 0 ? threadReplies[^1].SentAt : threadRootMessage.SentAt);
    }

    private void CloseThread()
    {
        isThreadOpen = false;
        threadRootMessage = null;
        threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (activeChannel is null || threadRootMessage is null) return;
        var reply = await ChatService.SendMessageAsync(activeChannel.Id, content, threadRootMessage.Id);
        threadReplies.Add(reply);

        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
            threadRootMessage.Id,
            threadReplies.Count,
            reply.SentAt);
    }

    private async Task AddReaction((int MessageId, string Emoji) reaction)
    {
        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);

        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId);
        if (msg is not null)
        {
            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
            if (existing is not null)
            {
                if (!existing.Users.Contains("You"))
                    existing.Users.Add("You");
            }
            else
            {
                msg.Reactions.Add(new Reaction(reaction.Emoji, ["You"]));
            }
        }
    }
}

.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

